        self.dev_tools_coverage_results = {
            'summary': {
                'total_issues': total_missed,
                'files_affected': 0,
            },
            'details': {
                'overall': {
                    'overall_coverage': overall_coverage,
                    'total_statements': total_statements,
                    'total_missed': total_missed
                },
                'modules': module_data,
                'coverage_collected': True,
